-- Workforce Solution: seed Kansas City–area Chipotle stores
-- Source: chipotle_stores.csv (Google Places search around 38.888, -94.683)
-- Adds a place_id column so re-running this is idempotent and we can re-sync
-- from Google Places later without duplicating rows.

alter table public.stores
  add column if not exists place_id text unique;

on conflict (place_id) do nothing;
